import React, { useState } from 'react';

interface FormData {
  name: string;
  email: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  message?: string;
}

const ContactForm: React.FC = () => {
  const [formData, setFormData] = useState<FormData>({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'success' | 'error' | null>(null);

  const validate = (): FormErrors => {
    const newErrors: FormErrors = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required.';
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required.';
    } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
      newErrors.email = 'Email address is invalid.';
    }
    if (!formData.message.trim()) newErrors.message = 'Message is required.';
    return newErrors;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const validationErrors = validate();
    setErrors(validationErrors);
    if (Object.keys(validationErrors).length === 0) {
      setIsSubmitting(true);
      setSubmitStatus(null);
      // Simulate API call
      try {
        await new Promise(resolve => setTimeout(resolve, 1000));
        console.log('Form Data Submitted:', formData);
        setSubmitStatus('success');
        setFormData({ name: '', email: '', message: '' });
      } catch (error) {
        setSubmitStatus('error');
      } finally {
        setIsSubmitting(false);
      }
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 sm:p-6 lg:p-8 bg-white rounded-xl shadow-lg">
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Get in Touch</h2>
      {submitStatus === 'success' && <div className="mb-4 p-4 text-sm text-green-700 bg-green-100 rounded-lg">Message sent successfully!</div>}
      {submitStatus === 'error' && <div className="mb-4 p-4 text-sm text-red-700 bg-red-100 rounded-lg">Failed to send message. Please try again.</div>}
      <form onSubmit={handleSubmit} noValidate>
        <div className="mb-5">
          <label htmlFor="name" className="block mb-2 text-sm font-medium text-gray-900">Full Name</label>
          <input type="text" id="name" name="name" value={formData.name} onChange={handleChange} className={`bg-gray-50 border ${errors.name ? 'border-red-500' : 'border-gray-300'} text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5`} required aria-describedby="name-error" />
          {errors.name && <p id="name-error" className="mt-2 text-sm text-red-600">{errors.name}</p>}
        </div>
        <div className="mb-5">
          <label htmlFor="email" className="block mb-2 text-sm font-medium text-gray-900">Email Address</label>
          <input type="email" id="email" name="email" value={formData.email} onChange={handleChange} className={`bg-gray-50 border ${errors.email ? 'border-red-500' : 'border-gray-300'} text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5`} required aria-describedby="email-error" />
          {errors.email && <p id="email-error" className="mt-2 text-sm text-red-600">{errors.email}</p>}
        </div>
        <div className="mb-5">
          <label htmlFor="message" className="block mb-2 text-sm font-medium text-gray-900">Your Message</label>
          <textarea id="message" name="message" rows={4} value={formData.message} onChange={handleChange} className={`block p-2.5 w-full text-sm text-gray-900 bg-gray-50 rounded-lg border ${errors.message ? 'border-red-500' : 'border-gray-300'} focus:ring-blue-500 focus:border-blue-500`} required aria-describedby="message-error"></textarea>
          {errors.message && <p id="message-error" className="mt-2 text-sm text-red-600">{errors.message}</p>}
        </div>
        <button type="submit" disabled={isSubmitting} className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-medium rounded-lg text-sm w-full sm:w-auto px-5 py-2.5 text-center disabled:bg-gray-400">
          {isSubmitting ? 'Sending...' : 'Send Message'}
        </button>
      </form>
    </div>
  );
};

export default ContactForm;

